parts.content:
apiVersion: v1
data:
  default.conf.template: |
    server {
        listen 80;
        location = /healthz {
            return 200 "ok\n";
            access_log off;
        }
        location / {
            proxy_pass ${REQUIRED_API_BASE};
        }
    }
kind: ConfigMap
metadata:
  labels:
    kustomize.toolkit.fluxcd.io/name: flux-system
    kustomize.toolkit.fluxcd.io/namespace: flux-system
  name: vigil-app-nginx-config
  namespace: default

parts.args:
{"title":"fix: correct nginx image tag in vigil-app deployment","body":"Root cause: Declared manifest specifies invalid nginx image tag 'nginx:declared-missing' that causes ImagePullBackOff

Evidence: Failed to pull image "nginx:live-missing": rpc error: code = NotFound desc = failed to pull and unpack image "docker.io/library/nginx:live-missing": failed to resolve reference "docker.io/library/nginx:live-missing": docker.io/library/nginx:live-missing: not found

This fix changes the image tag from 'nginx:declared-missing' to 'nginx:stable' to resolve the ImagePullBackOff issue."}

